# ─── API функциялар ─────────────────────────────────────────────────────────

def get_quiz(grade: int) -> list:
    """Нақты сыныптың тест сұрақтарын қайтарады"""
    return QUIZ_BANK.get(grade, [])

def count_questions(grade: int) -> int:
    """Сыныптағы сұрақтар санын қайтарады"""
    return len(QUIZ_BANK.get(grade, []))

def get_by_topic(grade: int, topic: str) -> list:
    """Тақырып бойынша сұрақтарды қайтарады"""
    return [q for q in QUIZ_BANK.get(grade, []) if q.get("topic") == topic]

def all_stats() -> dict:
    """Барлық сыныптар сұрақтар санын қайтарады"""
    return {g: len(qs) for g, qs in QUIZ_BANK.items()}
